def write_files(base_path: Path):
    files = FILES_JSON
    for relpath, info in files.items():
        target = base_path / relpath
        target.parent.mkdir(parents=True, exist_ok=True)
        if info['type'] == 'text':
            target.write_text(info['content'], encoding='utf-8')
        else:
            target.write_bytes(base64.b64decode(info['content']))


def validate_files(base_path: Path):
    files = FILES_JSON
    mismatches = []
    for relpath, info in files.items():
        target = base_path / relpath
        if not target.exists():
            mismatches.append((relpath, 'missing'))
            continue
        if info['type'] == 'text':
            existing = target.read_text(encoding='utf-8')
            if existing != info['content']:
                mismatches.append((relpath, 'content mismatch'))
        else:
            existing = target.read_bytes()
            expected = base64.b64decode(info['content'])
            if existing != expected:
                mismatches.append((relpath, 'content mismatch'))
    return mismatches


def main():
    base = Path('.')
    if '--write' in sys.argv:
        write_files(base)
        print('Wrote', len(FILES_JSON), 'files to', base)
    elif '--validate' in sys.argv:
        mismatches = validate_files(base)
        if mismatches:
            print('Validation failed:')
            for relpath, reason in mismatches[:20]:
                print(' ', reason, relpath)
            print(f"{len(mismatches)} mismatched files")
            sys.exit(1)
        print('Validation passed: all embedded files match current disk contents')
    else:
        print('Usage: python3 go.py --write | --validate')


if __name__ == '__main__':
    main()
